import React, { useEffect, useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import authService from '../services/authService';

export default function Login() {
    const navigate = useNavigate();
    const { login, isAuthenticated, isAdmin } = useAuth();
    const [formData, setFormData] = useState({
        email: '',
        password: '',
    });
    const [error, setError] = useState('');
    const [message, setMessage] = useState('');
    const [loading, setLoading] = useState(false);
    const [showSlowNetworkHint, setShowSlowNetworkHint] = useState(false);
    const [forgotLoading, setForgotLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);

    useEffect(() => {
        if (isAuthenticated) {
            navigate(isAdmin ? '/admin/dashboard' : '/dashboard', { replace: true });
        }
    }, [isAuthenticated, isAdmin, navigate]);

    useEffect(() => {
        if (!loading) {
            setShowSlowNetworkHint(false);
            return undefined;
        }

        const timer = setTimeout(() => {
            setShowSlowNetworkHint(true);
        }, 1200);

        return () => clearTimeout(timer);
    }, [loading]);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData((prev) => ({ ...prev, [name]: value }));
        setError('');
        setMessage('');
    };

    const handleForgotPassword = async () => {
        const email = formData.email.trim().toLowerCase();

        if (!email) {
            setMessage('');
            setError('Enter your email first, then click Forgot password.');
            return;
        }

        setForgotLoading(true);
        setError('');
        setMessage('');

        try {
            const response = await authService.forgotPassword({ email });
            const apiMessage = response?.data?.message || 'Reset link sent. Please check your email inbox.';
            const fallbackLink = response?.data?.reset_link || '';

            if (fallbackLink) {
                setMessage('Opening secure reset page...');
                window.location.assign(fallbackLink);
                return;
            }

            setMessage(apiMessage);
        } catch (err) {
            setError(err.response?.data?.message || 'Unable to send reset link. Please try again.');
        } finally {
            setForgotLoading(false);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setShowSlowNetworkHint(false);
        setLoading(true);
        setError('');

        try {
            const normalizedEmail = formData.email.trim().toLowerCase();
            const authData = await login(normalizedEmail, formData.password);
            if (authData?.user?.role === 'admin') {
                navigate('/admin/dashboard', { replace: true });
            } else {
                navigate('/dashboard', { replace: true });
            }
        } catch (err) {
            setError(err.response?.data?.message || 'Login failed. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="auth-page">
            <div className="auth-container">
                <div className="auth-modal auth-modal--login">
                    <div className="auth-modal__header">
                        <h1>Welcome Back!</h1>
                        <button 
                            type="button" 
                            className="auth-modal__close" 
                            aria-label="Close dialog"
                            onClick={() => navigate('/')}
                        >
                            ×
                        </button>
                    </div>

                    <div className="auth-modal__body">
                        {error && <div className="alert alert-danger">{error}</div>}
                        {message && <div className="alert alert-success">{message}</div>}
                        {loading && showSlowNetworkHint && (
                            <div className="alert alert-info" role="status">
                                Signing you in. Network is a bit slow, please wait...
                            </div>
                        )}

                        <form onSubmit={handleSubmit} className="auth-form">
                            <div className="form-group">
                                <label htmlFor="email">Email address</label>
                                <input
                                    type="email"
                                    id="email"
                                    name="email"
                                    value={formData.email}
                                    onChange={handleChange}
                                    placeholder="name@example.com"
                                    required
                                    disabled={loading}
                                />
                            </div>

                            <div className="form-group">
                                <label htmlFor="password">Password</label>
                                <div className="auth-password-field">
                                    <input
                                        type={showPassword ? 'text' : 'password'}
                                        id="password"
                                        name="password"
                                        value={formData.password}
                                        onChange={handleChange}
                                        placeholder="Enter your password"
                                        required
                                        disabled={loading}
                                    />
                                    <button
                                        type="button"
                                        className="auth-password-toggle auth-password-toggle--icon"
                                        onClick={() => setShowPassword((prev) => !prev)}
                                        disabled={loading}
                                        aria-label={showPassword ? 'Hide password' : 'Show password'}
                                    >
                                        {showPassword ? (
                                            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" aria-hidden="true">
                                                <path d="M3 3l18 18" />
                                                <path d="M10.58 10.58A2 2 0 0 0 12 15a2 2 0 0 0 1.42-.58" />
                                                <path d="M9.88 5.08A10.94 10.94 0 0 1 12 5c4.5 0 8.5 2.5 10 7-1.14 3.4-3.8 5.68-7 6.8" />
                                                <path d="M6.61 6.61C4.52 8.01 3 10.13 2 12c1.64 3.05 4.44 5.54 8 6.53" />
                                            </svg>
                                        ) : (
                                            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" aria-hidden="true">
                                                <path d="M2 12s3.5-7 10-7 10 7 10 7-3.5 7-10 7-10-7-10-7Z" />
                                                <circle cx="12" cy="12" r="3" />
                                            </svg>
                                        )}
                                    </button>
                                </div>
                            </div>

                            <div className="auth-row auth-row--split">
                                <label className="auth-checkbox auth-checkbox--inline">
                                    <input type="checkbox" disabled={loading} />
                                    <span>Remember me</span>
                                </label>
                                <button
                                    type="button"
                                    className="auth-link-muted auth-link-button"
                                    onClick={handleForgotPassword}
                                    disabled={loading || forgotLoading}
                                >
                                    {forgotLoading ? (
                                        <>
                                            <span className="auth-inline-spinner" aria-hidden="true" />
                                            Sending...
                                        </>
                                    ) : 'Forgot password?'}
                                </button>
                            </div>

                            <button
                                type="submit"
                                className="btn btn-primary btn-block"
                                disabled={loading}
                                aria-busy={loading}
                            >
                                {loading ? (
                                    <>
                                        <span className="auth-inline-spinner" aria-hidden="true" />
                                        Signing In...
                                    </>
                                ) : 'Sign In'}
                            </button>

                        </form>

                        <div className="auth-footer auth-footer--center">
                            <p>Don't have an account? <Link to="/register">Register now</Link></p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}
